import{_ as i,o as a,c as r,a4 as t}from"./chunks/framework.wrug7QjT.js";const h=JSON.parse('{"title":"Country Recommendations","description":"Top trans-friendly countries per continent with budget picks and best-for-asylum picks. Rankings based on trans-specific criteria plus Equaldex scores.","frontmatter":{"layout":"doc","title":"Country Recommendations","description":"Top trans-friendly countries per continent with budget picks and best-for-asylum picks. Rankings based on trans-specific criteria plus Equaldex scores."},"headers":[],"relativePath":"recommendations.md","filePath":"recommendations.md","lastUpdated":1781028538000}'),n={name:"recommendations.md"};function o(s,e,l,c,g,u){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="top-country-recommendations" tabindex="-1">Top Country Recommendations <a class="header-anchor" href="#top-country-recommendations" aria-label="Permalink to &quot;Top Country Recommendations&quot;">​</a></h1><p>Below are our top picks for trans-friendly relocation by continent. Each continent lists a <strong>top score pick</strong> (highest overall trans-friendliness), a <strong>budget pick</strong> (good rights at lower cost), and a <strong>best for asylum seekers</strong> pick (for those fleeing persecution). Rankings are based on trans-specific criteria: legal gender recognition model, healthcare access, safety, and community support — not just Equaldex scores.</p><div class="warning custom-block"><p class="custom-block-title">⚠️ About the Equaldex scores</p><p>The <a href="https://www.equaldex.com/equality-index" target="_blank" rel="noreferrer">Equaldex Equality Index</a> measures LGBTQ+ equality broadly — including same-sex marriage, adoption, and sexual orientation laws. It is <strong>not trans-specific</strong>. A country with a high Equaldex score may still have barriers to trans healthcare, gender recognition, or community safety. Where possible, this page uses trans-specific criteria in addition to Equaldex data.</p></div><h2 id="europe" tabindex="-1">Europe <a class="header-anchor" href="#europe" aria-label="Permalink to &quot;Europe&quot;">​</a></h2><p>Europe has the highest concentration of trans-friendly countries in the world, with 14 of the top 20 countries globally for trans rights. The European Union provides a baseline of non-discrimination protections, though individual countries vary enormously.</p><h3 id="🥇-top-score-pick-malta" tabindex="-1">🥇 Top Score Pick: Malta <a class="header-anchor" href="#🥇-top-score-pick-malta" aria-label="Permalink to &quot;🥇 Top Score Pick: Malta&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (2015)</li><li><strong>Healthcare:</strong> Informed consent, publicly funded</li><li><strong>Equaldex score:</strong> 93</li><li><strong>Trans-specific rating:</strong> 5/5</li><li><strong>Why:</strong> Consistently ranked #1 in ILGA Europe. Constitutional protections for gender identity. Banned conversion therapy. Self-ID for all legal documents. Informed consent healthcare model with public coverage.</li><li><strong>Consider:</strong> Small geographic size limits housing options. Job market is limited outside certain sectors (iGaming, financial services). Not ideal for asylum seekers due to distance from continental Europe and limited refugee infrastructure.</li></ul><h3 id="🥈-runner-up-iceland" tabindex="-1">🥈 Runner-Up: Iceland <a class="header-anchor" href="#🥈-runner-up-iceland" aria-label="Permalink to &quot;🥈 Runner-Up: Iceland&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (2019)</li><li><strong>Healthcare:</strong> Informed consent (public, but long wait times)</li><li><strong>Equaldex score:</strong> 93</li><li><strong>Trans-specific rating:</strong> 5/5</li><li><strong>Why:</strong> Pioneer in trans rights. Hate crime laws explicitly include gender identity. Excellent social safety net.</li><li><strong>Consider:</strong> Very high cost of living. Small population means limited dating pool and community. Harsh weather. Very difficult immigration for non-EU citizens.</li></ul><h3 id="💰-budget-pick-portugal" tabindex="-1">💰 Budget Pick: Portugal <a class="header-anchor" href="#💰-budget-pick-portugal" aria-label="Permalink to &quot;💰 Budget Pick: Portugal&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (2018)</li><li><strong>Healthcare:</strong> Informed consent (some gatekeeping)</li><li><strong>Equaldex score:</strong> 84</li><li><strong>Trans-specific rating:</strong> 4/5</li><li><strong>Why:</strong> Self-declaration legal. Affordable cost of living by Western European standards. Excellent digital nomad visa options. Good healthcare system with strong trans support organisations (GAT, ILGA Portugal).</li><li><strong>Consider:</strong> Portuguese language required for full integration. Salaries are among the lowest in Western Europe. Housing crisis in Lisbon and Porto makes finding affordable accommodation difficult.</li></ul><h3 id="🏛️-best-for-asylum-seekers-germany" tabindex="-1">🏛️ Best for Asylum Seekers: Germany <a class="header-anchor" href="#🏛️-best-for-asylum-seekers-germany" aria-label="Permalink to &quot;🏛️ Best for Asylum Seekers: Germany&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (SBGG, 1 November 2024)</li><li><strong>Healthcare:</strong> Informed consent (varies by state)</li><li><strong>Equaldex score:</strong> 87</li><li><strong>Trans-specific rating:</strong> 4/5</li><li><strong>Why:</strong> Strong asylum grant rates for LGBTQ+ claims (60–80%). Large refugee support infrastructure. Extensive trans healthcare network. Multiple visa options beyond asylum (freelancer, student, work). Central European location makes travel to other safe countries easy.</li><li><strong>Consider:</strong> Language barrier (B1 German required for citizenship). Bureaucracy is slow and inflexible. Trans healthcare access depends heavily on which city you live in. Rising far-right political influence in some regions.</li></ul><h2 id="north-america" tabindex="-1">North America <a class="header-anchor" href="#north-america" aria-label="Permalink to &quot;North America&quot;">​</a></h2><h3 id="🥇-top-score-pick-canada" tabindex="-1">🥇 Top Score Pick: Canada <a class="header-anchor" href="#🥇-top-score-pick-canada" aria-label="Permalink to &quot;🥇 Top Score Pick: Canada&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (varies by province)</li><li><strong>Healthcare:</strong> Informed consent (varies by province)</li><li><strong>Equaldex score:</strong> 92</li><li><strong>Trans-specific rating:</strong> 5/5</li><li><strong>Why:</strong> Strongest trans protections in North America. Public healthcare covers gender-affirming care (including surgeries) in most provinces. Excellent asylum grant rates for LGBTQ+ claims (70–85%). Large trans communities in Toronto, Vancouver, and Montreal. Private refugee sponsorship program.</li><li><strong>Consider:</strong> Very high cost of living in major cities. Harsh winters outside of Vancouver. Immigration system is points-based and can be slow. Healthcare wait times for non-emergency care are long nationwide.</li></ul><h3 id="💰-budget-pick-mexico" tabindex="-1">💰 Budget Pick: Mexico <a class="header-anchor" href="#💰-budget-pick-mexico" aria-label="Permalink to &quot;💰 Budget Pick: Mexico&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Varies by state (Mexico City and some states have self-ID)</li><li><strong>Healthcare:</strong> Mixed (private informed consent available in major cities)</li><li><strong>Equaldex score:</strong> 65</li><li><strong>Trans-specific rating:</strong> 3/5</li><li><strong>Why:</strong> Relatively affordable cost of living. Progressive laws in Mexico City (self-ID since 2020). Large trans community and visible activism. Easy entry for many nationalities.</li><li><strong>Consider:</strong> Safety varies enormously by region. Legal protections inconsistent outside of major cities. Healthcare for trans people is mixed — good private options in CDMX, limited elsewhere. Language barrier (Spanish essential).</li></ul><h3 id="🏛️-best-for-asylum-seekers-canada" tabindex="-1">🏛️ Best for Asylum Seekers: Canada <a class="header-anchor" href="#🏛️-best-for-asylum-seekers-canada" aria-label="Permalink to &quot;🏛️ Best for Asylum Seekers: Canada&quot;">​</a></h3><ul><li><strong>Why:</strong> Highest grant rates in North America for LGBTQ+ asylum claims. Private refugee sponsorship program (Groups of 5+ Canadians can sponsor a refugee). Interim Federal Health Program covers HRT and gender-affirming care for resettled refugees. Strong community sponsorship infrastructure.</li></ul><h2 id="south-america" tabindex="-1">South America <a class="header-anchor" href="#south-america" aria-label="Permalink to &quot;South America&quot;">​</a></h2><h3 id="🥇-top-score-pick-argentina" tabindex="-1">🥇 Top Score Pick: Argentina <a class="header-anchor" href="#🥇-top-score-pick-argentina" aria-label="Permalink to &quot;🥇 Top Score Pick: Argentina&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (2012 — first in Latin America)</li><li><strong>Healthcare:</strong> Informed consent, public coverage of gender-affirming care</li><li><strong>Equaldex score:</strong> 87</li><li><strong>Trans-specific rating:</strong> 5/5</li><li><strong>Why:</strong> The most progressive trans rights framework in Latin America and arguably the world. Self-ID since 2012 without any medical requirements. Public healthcare system covers HRT and gender-affirming surgeries. Active trans rights movement. Strong legal framework against discrimination.</li><li><strong>Consider:</strong> Severe economic instability (inflation, currency devaluation). Safety has declined in recent years. Spanish essential for integration. Political climate is unpredictable (2024–2025 saw some rollback signals under new administration). Visa pathway for non-Mercosur citizens is limited.</li></ul><h3 id="💰-budget-pick-chile" tabindex="-1">💰 Budget Pick: Chile <a class="header-anchor" href="#💰-budget-pick-chile" aria-label="Permalink to &quot;💰 Budget Pick: Chile&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (2019 Gender Identity Law)</li><li><strong>Healthcare:</strong> Mixed (public covers HRT, private offers faster access)</li><li><strong>Equaldex score:</strong> 74</li><li><strong>Trans-specific rating:</strong> 4/5</li><li><strong>Why:</strong> Strong Gender Identity Law (2019) allows self-ID for 14+. Relatively stable economy compared to neighbours. Growing trans community in Santiago.</li><li><strong>Consider:</strong> High cost of living in Santiago. Social conservatism outside of major cities. Healthcare access is slower on public system. Spanish essential.</li></ul><h3 id="🏛️-best-for-asylum-seekers-brazil" tabindex="-1">🏛️ Best for Asylum Seekers: Brazil <a class="header-anchor" href="#🏛️-best-for-asylum-seekers-brazil" aria-label="Permalink to &quot;🏛️ Best for Asylum Seekers: Brazil&quot;">​</a></h3><ul><li><strong>Why:</strong> Progressive legal framework (self-ID by Supreme Court ruling 2018; public SUS covers gender-affirming care). Large trans community. Relatively open visa policies for many nationalities. However, safety is a major concern — Brazil has the highest trans murder rate in the world. Asylum claims from within South America face higher scrutiny.</li></ul><h2 id="oceania" tabindex="-1">Oceania <a class="header-anchor" href="#oceania" aria-label="Permalink to &quot;Oceania&quot;">​</a></h2><h3 id="🥇-top-score-pick-new-zealand" tabindex="-1">🥇 Top Score Pick: New Zealand <a class="header-anchor" href="#🥇-top-score-pick-new-zealand" aria-label="Permalink to &quot;🥇 Top Score Pick: New Zealand&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (2021 — Births, Deaths, Marriages, and Relationships Registration Act)</li><li><strong>Healthcare:</strong> Informed consent</li><li><strong>Equaldex score:</strong> 84</li><li><strong>Trans-specific rating:</strong> 5/5</li><li><strong>Why:</strong> Self-ID by simple declaration. Strong healthcare system with informed consent widely available. Comprehensive anti-discrimination laws. Very safe society. Welcoming culture for migrants.</li><li><strong>Consider:</strong> Extremely remote — expensive and time-consuming to travel to/from. Very high cost of living (Auckland and Wellington comparable to London). Job market is small. Housing crisis in major cities. Visa pathways are limited for non-EU/non-US citizens outside of Green List skilled work.</li></ul><h3 id="🥈-runner-up-australia" tabindex="-1">🥈 Runner-Up: Australia <a class="header-anchor" href="#🥈-runner-up-australia" aria-label="Permalink to &quot;🥈 Runner-Up: Australia&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Self-ID (varies by state; federal process still medicalised)</li><li><strong>Healthcare:</strong> Informed consent</li><li><strong>Equaldex score:</strong> 83</li><li><strong>Trans-specific rating:</strong> 4/5</li><li><strong>Why:</strong> Strong protections in most states. Large trans communities in Sydney, Melbourne, and Brisbane. Good healthcare options with informed consent widely available.</li><li><strong>Consider:</strong> Visa system is complex and expensive. Federal vs. state inconsistency on gender recognition (some states require surgery for birth certificate change). High cost of living in major cities. Not ideal for low-income migrants.</li></ul><h3 id="💰-budget-pick-n-a-for-oceania" tabindex="-1">💰 Budget Pick: N/A for Oceania <a class="header-anchor" href="#💰-budget-pick-n-a-for-oceania" aria-label="Permalink to &quot;💰 Budget Pick: N/A for Oceania&quot;">​</a></h3><ul><li>Neither Australia nor New Zealand are budget destinations. Both have high minimum wages but also very high costs of living.</li></ul><h3 id="🏛️-best-for-asylum-seekers-new-zealand" tabindex="-1">🏛️ Best for Asylum Seekers: New Zealand <a class="header-anchor" href="#🏛️-best-for-asylum-seekers-new-zealand" aria-label="Permalink to &quot;🏛️ Best for Asylum Seekers: New Zealand&quot;">​</a></h3><ul><li><strong>Why:</strong> The Pacific Green List provides a streamlined path to residency for skilled workers. Asylum grant rates for LGBTQ+ claims are reasonable (~50–65%). However, New Zealand is very far from most origin countries and the refugee quota is small.</li></ul><h2 id="east-asia" tabindex="-1">East Asia <a class="header-anchor" href="#east-asia" aria-label="Permalink to &quot;East Asia&quot;">​</a></h2><h3 id="🥇-top-score-pick-taiwan" tabindex="-1">🥇 Top Score Pick: Taiwan <a class="header-anchor" href="#🥇-top-score-pick-taiwan" aria-label="Permalink to &quot;🥇 Top Score Pick: Taiwan&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Medicalised (surgery required for gender marker change, but legal challenges ongoing)</li><li><strong>Healthcare:</strong> Gatekeeping (but informed consent available in some clinics)</li><li><strong>Equaldex score:</strong> 60</li><li><strong>Trans-specific rating:</strong> 3/5</li><li><strong>Why:</strong> Most progressive country in Asia for LGBTQ+ rights. First Asian country to legalise same-sex marriage (2019). Strong social acceptance in Taipei. Growing trans visibility.</li><li><strong>Consider:</strong> Surgery requirement for gender recognition is a major barrier. Legal framework is inconsistent — protections exist but enforcement is weak. Geopolitical situation is a concern for long-term stability. Mandarin essential for integration. Not suitable for asylum seekers (Taiwan&#39;s asylum system is limited).</li></ul><h3 id="🥈-runner-up-japan" tabindex="-1">🥈 Runner-Up: Japan <a class="header-anchor" href="#🥈-runner-up-japan" aria-label="Permalink to &quot;🥈 Runner-Up: Japan&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Medicalised (surgery + sterilization required, but 2023 Supreme Court ruling found sterilization requirement unconstitutional)</li><li><strong>Healthcare:</strong> Gatekeeping</li><li><strong>Equaldex score:</strong> 33</li><li><strong>Trans-specific rating:</strong> 2/5</li><li><strong>Why:</strong> 2023 Supreme Court ruling was a positive step. Tokyo has visible LGBTQ+ spaces. Increasing corporate support for LGBTQ+ inclusion. Safe country with low crime rates.</li><li><strong>Consider:</strong> Surgery requirement still effectively in place (court ruling did not automatically change the law). No federal anti-discrimination protections. Social conservatism is strong outside of major cities. Japanese language essential for healthcare and daily life. No asylum pathway for LGBTQ+ claims.</li></ul><h3 id="💰-budget-pick-thailand" tabindex="-1">💰 Budget Pick: Thailand <a class="header-anchor" href="#💰-budget-pick-thailand" aria-label="Permalink to &quot;💰 Budget Pick: Thailand&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Medicalised (surgery required)</li><li><strong>Healthcare:</strong> Informed consent (many private clinics)</li><li><strong>Equaldex score:</strong> 48</li><li><strong>Trans-specific rating:</strong> 3/5</li><li><strong>Why:</strong> Very affordable cost of living. Large trans (kathoey) community with cultural visibility. Many trans-friendly private clinics for HRT and surgeries at low cost. Marriage Equality Act (2024) legalised same-sex marriage.</li><li><strong>Consider:</strong> Gender recognition still requires surgery. No federal anti-discrimination law. Social acceptance is complex — kathoey identity is recognised but distinct from Western trans identity. Visa pathways for long-term residence are limited. Not suitable for asylum seekers.</li></ul><h3 id="🏛️-best-for-asylum-seekers-n-a-for-east-asia" tabindex="-1">🏛️ Best for Asylum Seekers: N/A for East Asia <a class="header-anchor" href="#🏛️-best-for-asylum-seekers-n-a-for-east-asia" aria-label="Permalink to &quot;🏛️ Best for Asylum Seekers: N/A for East Asia&quot;">​</a></h3><ul><li>No East Asian country has a functioning asylum system for LGBTQ+ claims. This region is not recommended for people fleeing persecution.</li></ul><h2 id="africa" tabindex="-1">Africa <a class="header-anchor" href="#africa" aria-label="Permalink to &quot;Africa&quot;">​</a></h2><h3 id="🥇-top-score-pick-south-africa" tabindex="-1">🥇 Top Score Pick: South Africa <a class="header-anchor" href="#🥇-top-score-pick-south-africa" aria-label="Permalink to &quot;🥇 Top Score Pick: South Africa&quot;">​</a></h3><ul><li><strong>Legal recognition:</strong> Medicalised (requires surgery or court order)</li><li><strong>Healthcare:</strong> Limited public; private informed consent available</li><li><strong>Equaldex score:</strong> 58</li><li><strong>Trans-specific rating:</strong> 2/5</li><li><strong>Why:</strong> Only country in Africa with constitutional protections for sexual orientation and gender identity (since 1996). Legal same-sex marriage since 2006. Active trans community and legal advocacy organisations.</li><li><strong>Consider:</strong> Extremely high levels of violence against trans people. Weak enforcement of legal protections. Healthcare access is very limited on public system (private is expensive). Surgical requirement for gender recognition is a major barrier. Safety is a serious concern — South Africa has one of the highest rates of violent crime in the world.</li></ul><h3 id="💰-budget-pick-n-a" tabindex="-1">💰 Budget Pick: N/A <a class="header-anchor" href="#💰-budget-pick-n-a" aria-label="Permalink to &quot;💰 Budget Pick: N/A&quot;">​</a></h3><ul><li>No African country offers both trans safety and affordability. South Africa is the only country with legal protections, but safety is poor.</li></ul><h3 id="🏛️-best-for-asylum-seekers-n-a" tabindex="-1">🏛️ Best for Asylum Seekers: N/A <a class="header-anchor" href="#🏛️-best-for-asylum-seekers-n-a" aria-label="Permalink to &quot;🏛️ Best for Asylum Seekers: N/A&quot;">​</a></h3><ul><li>African asylum claims are generally processed outside of Africa (applicants must reach a safe third country first). Rainbow Railroad, UNHCR, and ORAM can assist with evacuation to non-African destinations.</li></ul><p><strong>Honest note on Africa:</strong> The situation for trans people across the African continent is difficult. Many countries criminalise LGBTQ+ identity (Nigeria, Uganda, Ghana, Kenya, Zimbabwe, among others). Even in countries without explicit criminalisation, social hostility is high. This site does not currently recommend any African country as a safe relocation destination for transgender individuals. If you are in Africa and need to leave, focus on reaching a transit country and contacting Rainbow Railroad or UNHCR for evacuation. See the <a href="/transit/asylum/">Asylum page</a> and <a href="/transit/emergency/">Emergency page</a>.</p><h2 id="how-we-rank" tabindex="-1">How We Rank <a class="header-anchor" href="#how-we-rank" aria-label="Permalink to &quot;How We Rank&quot;">​</a></h2><p>Each pick is evaluated on five trans-specific criteria:</p><ol><li><strong>Legal recognition model</strong> (self-ID preferred over medicalised)</li><li><strong>Healthcare access</strong> (informed consent, public coverage, wait times)</li><li><strong>Safety</strong> (hate crime rates, police protection, social acceptance)</li><li><strong>Visa pathway</strong> (availability, cost, speed, path to permanent residency)</li><li><strong>Community</strong> (size of trans population, organised groups, visibility)</li></ol><p>The <a href="https://www.equaldex.com/equality-index" target="_blank" rel="noreferrer">Equaldex Equality Index</a> is used as a supplementary reference only, with the understanding that it measures broad LGBTQ+ equality and is not trans-specific.</p><p><em>Last verified: June 8, 2026. Rankings are based on conditions as of June 8, 2026 and may change. Country situations, legal frameworks, and healthcare access evolve — always verify with current sources before making relocation decisions.</em></p>',58)])])}const m=i(n,[["render",o]]);export{h as __pageData,m as default};
